const teams = [];

function slugify(text) {
  return String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // quitar acentos
    .replace(/[^a-z0-9]+/g, "-")     // espacios y símbolos a guión
    .replace(/^-+|-+$/g, "");        // quitar guiones al inicio/final
}

for (const item of items) {
  const areaCode = item.json.area_code || null;
  const areaName = item.json.area_name || null;

  const homeName = item.json.home_team_name || null;
  const awayName = item.json.away_team_name || null;

  const home = {
    id: Number(item.json.home_team_id),
    name: homeName,
    slug: slugify(homeName),
    country_code: areaCode,
    country_name: areaName,
  };

  const away = {
    id: Number(item.json.away_team_id),
    name: awayName,
    slug: slugify(awayName),
    country_code: areaCode,
    country_name: areaName,
  };

  teams.push(home, away);
}

// eliminar duplicados por id
const unique = Object.values(
  teams.reduce((acc, team) => {
    acc[team.id] = team;
    return acc;
  }, {})
);

return unique.map((t) => ({
  json: t
}));
